// Generated by OrchestKit Claude Plugin
// Created: 2026-05-12
// Issue: #1783 (M139 Bundle A — A1 agent-view title tagger)

/**
 * Agent View Titler — SubagentStart Hook
 *
 * CC 2.1.139 introduced `claude agents` (Research Preview), which lists every
 * active CC session. Without a descriptive title, sessions show up as raw
 * UUIDs — unusable once 5+ background workers are in flight.
 *
 * This hook derives a short, human-readable title for each subagent at spawn
 * time and emits it on `hookSpecificOutput.sessionTitle` so the agent-view
 * row reads as something like:
 *
 *   [ork:backend-system-architect] design auth middleware refactor
 *
 * API surface caveat (honest):
 *   - CC 2.1.94 introduced `HookSpecificOutput.sessionTitle` for UserPromptSubmit.
 *   - CC 2.1.139 ships `claude agents` but does NOT document a hook contract
 *     for setting an agent-view title.
 *   - `HookSpecificOutput.hookEventName` enumerates `SubagentStart`, and the
 *     `sessionTitle` field is defined on the same shape — so emitting
 *     `{ hookEventName: 'SubagentStart', sessionTitle: ... }` is the most
 *     plausible wire-up, but it is inference, not documented behaviour.
 *   - Defense-in-depth: we also mirror the title into `additionalContext` so
 *     the title is *also* visible to the agent itself (and to any downstream
 *     consumer that scrapes context for display purposes). Cost: ~25 tokens.
 *
 * Title derivation rule:
 *   - If `subagent_type`/`agent_type` is set: `[ork:<name>] <prompt verb-phrase, 40 chars>`
 *   - Else: `<prompt body, 50 chars>`
 *   - Newlines collapsed to spaces; consecutive whitespace squeezed.
 *
 * Failure mode: fails open. Any thrown error returns `outputSilentSuccess()`
 * so we never block an agent spawn over a cosmetic feature.
 */

import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'agent-view-titler';

/** Max body length when an agent name is present. */
const NAMED_BODY_MAX = 40;

/** Max body length when no agent name is present. */
const ANONYMOUS_BODY_MAX = 50;

/** Prefix used for ork-managed agents in the title. */
const AGENT_PREFIX = 'ork';

/**
 * Collapse whitespace, drop control chars, trim.
 * Pure — no I/O, no regex catastrophe risk (linear scan).
 */
export function normalizePromptBody(raw: string | undefined): string {
  if (!raw) return '';
  // Replace any whitespace run (including newlines, tabs) with a single space.
  // Drop ASCII control chars (< 0x20) other than whitespace.
  let out = '';
  let prevSpace = false;
  for (let i = 0; i < raw.length; i++) {
    const code = raw.charCodeAt(i);
    const isSpace = code === 0x20 || code === 0x09 || code === 0x0a || code === 0x0d;
    if (isSpace) {
      if (!prevSpace && out.length > 0) out += ' ';
      prevSpace = true;
      continue;
    }
    if (code < 0x20) continue; // skip other control chars
    out += raw[i];
    prevSpace = false;
  }
  return out.trim();
}

/**
 * Truncate `body` to at most `max` chars. If truncation occurs, break on the
 * last word boundary inside the budget (when one exists past 60% of the
 * budget) and append a single-character ellipsis '…'.
 */
export function truncateBody(body: string, max: number): string {
  if (body.length <= max) return body;
  const hardCut = body.slice(0, max);
  const lastSpace = hardCut.lastIndexOf(' ');
  const minSoftCut = Math.floor(max * 0.6);
  const cutAt = lastSpace >= minSoftCut ? lastSpace : max;
  return `${body.slice(0, cutAt).replace(/[\s,;:.-]+$/, '')}…`;
}

/**
 * Resolve the agent name from the input. CC has used both `subagent_type`
 * (older) and `agent_type` (newer) — accept either.
 */
function resolveAgentName(input: HookInput): string | null {
  const raw = input.subagent_type ?? input.agent_type ?? null;
  if (!raw) return null;
  let cleaned = raw.trim();
  if (!cleaned) return null;
  // Strip a leading `ork:` segment so the title wrapper doesn't double-prefix:
  // [${AGENT_PREFIX}:${name}] with name="ork:foo" produced "[ork:ork:foo]".
  // Single-segment strip — `ork:foo:bar` becomes `foo:bar`, not `bar`.
  const colonIdx = cleaned.indexOf(':');
  if (colonIdx > 0 && colonIdx < cleaned.length - 1) {
    const prefix = cleaned.slice(0, colonIdx);
    if (prefix === AGENT_PREFIX) {
      cleaned = cleaned.slice(colonIdx + 1);
    }
  }
  // Defense: agent names should be kebab-case identifiers. Strip any chars
  // that aren't alnum / dash / colon / underscore to avoid title injection.
  return cleaned.replace(/[^A-Za-z0-9_\-:.]/g, '').slice(0, 64);
}

/**
 * Build the display title for the agent-view row.
 */
export function deriveTitle(input: HookInput): string | null {
  const body = normalizePromptBody(input.prompt);
  const agentName = resolveAgentName(input);

  if (agentName) {
    const truncated = truncateBody(body, NAMED_BODY_MAX);
    const tag = `[${AGENT_PREFIX}:${agentName}]`;
    return truncated.length > 0 ? `${tag} ${truncated}` : tag;
  }

  if (!body) return null; // nothing useful to show; let CC fall back to UUID
  return truncateBody(body, ANONYMOUS_BODY_MAX);
}

export function agentViewTitler(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  try {
    const title = deriveTitle(input);
    if (!title) {
      ctx.log(HOOK_NAME, 'No agent name or prompt body — skipping title');
      return outputSilentSuccess();
    }

    ctx.log(HOOK_NAME, `Setting agent-view title: ${title}`);

    // Dual-channel:
    //   1. hookSpecificOutput.sessionTitle  — primary; CC 2.1.94+ wire shape
    //   2. additionalContext                — fallback so the agent itself
    //      and any HQ/observability scraper sees its own title.
    return {
      continue: true,
      suppressOutput: true,
      hookSpecificOutput: {
        hookEventName: 'SubagentStart',
        sessionTitle: title,
        additionalContext: `[agent-view] title: ${title}`,
      },
    };
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    ctx.log(HOOK_NAME, `Unexpected error — failing open: ${message}`, 'warn');
    return outputSilentSuccess();
  }
}
